query:
-- 3.1 productConversions: não deve haver registros onde conversion.tenantId=1 E product.tenantId!=1
SELECT COUNT(*) AS incorretos_restantes_productConversions
FROM productConversions pc
JOIN products p ON p.id = pc.productId
WHERE pc.tenantId = 1
  AND p.tenantId IS NOT NULL
  AND p.tenantId != 1;

-- 3.2 labelAssociations: idem
SELECT COUNT(*) AS incorretos_restantes_labelAssociations
FROM labelAssociations la
JOIN products p ON p.id = la.productId
WHERE la.tenantId = 1
  AND p.tenantId IS NOT NULL
  AND p.tenantId != 1;

-- 3.3 Resumo final por tabela
SELECT 'productConversions' AS tabela, tenantId, COUNT(*) AS qtd FROM productConversions GROUP BY tenantId ORDER BY tenantId;
SELECT 'unitAliases' AS tabela, tenantId, COUNT(*) AS qtd FROM unitAliases GROUP BY tenantId ORDER BY tenantId;
SELECT 'labelAssociations' AS tabela, tenantId, COUNT(*) AS qtd FROM labelAssociations GROUP BY tenantId ORDER BY tenantId;
SELECT 'unitPendingQueue' AS tabela, tenantId, COUNT(*) AS qtd FROM unitPendingQueue GROUP BY tenantId ORDER BY tenantId;

